<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0;font-family:sans-serif;}
  body,html{height:100%;background:#222;color:#eee;overflow:hidden;}
  #desktop{position:absolute;width:100%;height:100%;}
  /* Taskbar */
  #taskbar{
    position:absolute;bottom:0;left:0;width:100%;height:40px;background:#111;
    display:flex;align-items:center;padding-left:10px;border-top:1px solid #444;
  }
  .launcher{background:#333;color:#eee;border:none;margin-right:5px;padding:8px 12px;
            cursor:pointer;font-size:14px;}
  /* Windows */
  .window{
    position:absolute;top:50px;left:50px;width:400px;height:300px;background:#333;
    border:1px solid #555;border-radius:4px;color:#eee;display:none;
    flex-direction:flex-column;overflow:hidden;
  }
  .win-header{background:#222;padding:5px 10px;cursor:pointer;display:flex;
               justify-content:space-between;align-items:center;}
  .win-close{background:#c00;border:none;color:white;padding:2px 6px;font-size:12px;
             cursor:pointer;}
  .win-body{flex:1;overflow:auto;padding:10px;background:#222;}
  /* Files app */
  #files-window{width:500px;height:400px;}
  #files-path{font-family:monospace;margin-bottom:5px;}
  .fs-item{padding:2px 0;cursor:pointer;}
  .fs-item:hover{background:#444;}
  #files-up{margin-top:10px;background:#555;color:white;border:none;padding:4px 8px;
            cursor:pointer;font-size:12px;}
  /* Notepad */
  #notepad-window{width:600px;height:500px;}
  #tabs{display:flex;flex-wrap:wrap;background:#222;}
  .tab{
    background:#444;color:#eee;border:none;padding:5px 10px;margin-right:2px;
    cursor:pointer;font-size:12px;position:relative;
  }
  .tab.active{background:#666;}
  #new-tab{background:#555;color:white;border:none;padding:5px 8px;
           cursor:pointer;font-size:12px;}
  #editor{width:100%;height:calc(100% - 30px);border:none;background:#111;color:#eee;
          font-family:monospace;font-size:14px;resize:none;}
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files" class="launcher">Files</button>
    <button id="open-notepad" class="launcher">Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="win-header">
      <span>Files</span>
      <button class="win-close">&times;</button>
    </div>
    <div class="win-body">
      <div id="files-path">/</div>
      <div id="file-list"></div>
      <button id="files-up">Up</button>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="win-header">
      <span>Notepad</span>
      <button class="win-close">&times;</button>
    </div>
    <div class="win-body" style="display:flex;flex-direction:column;">
      <div id="tabs"></div>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
/* ---------- Files App ---------- */
const fs = {
  '/': {type:'dir', children:{bin:{}, etc:{}, home:{user:{Documents:{},Downloads:{},Pictures:{}}}, usr:{}, var:{}}},
};
function getNode(path){
  const parts=path.split('/').filter(Boolean);
  let node=fs['/'];
  for(const p of parts){node=node.children[p];}
  return node;
}
let currentPath='/';
const fileList=document.getElementById('file-list');
const pathDisplay=document.getElementById('files-path');
function renderFiles(){
  const node=getNode(currentPath);
  fileList.innerHTML='';
  for(const name in node.children){
    const item=document.createElement('div');
    item.className='fs-item';
    item.textContent=name;
    item.dataset.name=name;
    if(node.children[name].type==='dir'){
      item.addEventListener('dblclick',()=>{navigate(name);});
    }
    fileList.appendChild(item);
  }
  pathDisplay.textContent=currentPath;
}
function navigate(folder){
  currentPath+=folder+'/';
  renderFiles();
}
document.getElementById('files-up').addEventListener('click',()=>{
  if(currentPath!=='/'){
    const parts=currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath='/' + parts.join('/') + (parts.length?'/':'');
    renderFiles();
  }
});
renderFiles();

/* ---------- Notepad App ---------- */
const STORAGE_KEY='notepad_tabs';
let tabs=[];
let activeIndex=0;
function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data)tabs=JSON.parse(data); else tabs=[{title:'Untitled',content:''}];
}
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}
function renderTabs(){
  const tabsDiv=document.getElementById('tabs');
  tabsDiv.innerHTML='';
  tabs.forEach((t,i)=>{
    const tabEl=document.createElement('div');
    tabEl.className='tab'+(i===activeIndex?' active':'');
    tabEl.textContent=t.title;
    tabEl.dataset.index=i;
    tabEl.addEventListener('click',()=>{switchTab(i);});
    tabsDiv.appendChild(tabEl);
  });
  const newBtn=document.createElement('button');
  newBtn.id='new-tab';
  newBtn.textContent='+';
  newBtn.addEventListener('click',addNewTab);
  tabsDiv.appendChild(newBtn);
}
function switchTab(idx){
  if(activeIndex===idx)return;
  document.getElementById('editor').value=tabs[activeIndex].content;
  activeIndex=idx;
  renderTabs();
  document.getElementById('editor').value=tabs[activeIndex].content;
}
function addNewTab(){
  tabs.push({title:'Untitled',content:''});
  activeIndex=tabs.length-1;
  renderTabs();
  document.getElementById('editor').value='';
}
const editor=document.getElementById('editor');
editor.addEventListener('input',()=>{
  tabs[activeIndex].content=editor.value;
  saveTabs();
});

loadTabs();
renderTabs();
document.getElementById('editor').value=tabs[activeIndex].content;

/* ---------- Window Controls ---------- */
function showWindow(id){
  document.getElementById(id).style.display='flex';
}
function hideWindow(id){
  document.getElementById(id).style.display='none';
}
document.getElementById('open-files').addEventListener('click',()=>showWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click',()=>showWindow('notepad-window'));
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click',()=>{
    hideWindow(btn.parentNode.parentNode.id);
  });
});
</script>
</body>
</html>
